import{_ as s,o as e,c as i,ak as t}from"./chunks/framework.Chu_0La1.js";const k=JSON.parse('{"title":"📈 高阶数据分析","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"help/sakura/advanced.md","filePath":"doc/help/sakura/advanced.md"}'),l={name:"help/sakura/advanced.md"};function n(d,a,p,r,h,c){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="📈-高阶数据分析" tabindex="-1">📈 高阶数据分析 <a class="header-anchor" href="#📈-高阶数据分析" aria-label="Permalink to “📈 高阶数据分析”">​</a></h1><div class="feature-hero" style="background:linear-gradient(135deg, #667eea 0%, #764ba2 100%);"><span class="feature-icon">📈</span><h2>高阶数据分析</h2><p>深度分析你的游戏数据，提供专业级的统计和洞察</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">数据要求</p><p>以下功能<strong>必须上传游戏数据</strong>才能使用。请先完成 <a href="./user-data">数据上传</a>。</p></div><hr><h2 id="排位与评分" tabindex="-1">排位与评分 <a class="header-anchor" href="#排位与评分" aria-label="Permalink to “排位与评分”">​</a></h2><div class="command-section"><h3 id="查看排位信息" tabindex="-1">查看排位信息 <a class="header-anchor" href="#查看排位信息" aria-label="Permalink to “查看排位信息”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>rk</span></span></code></pre></div><p>获取玩家当前排位信息。</p><h3 id="b39-分析" tabindex="-1">B39 分析 <a class="header-anchor" href="#b39-分析" aria-label="Permalink to “B39 分析”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>b39</span></span></code></pre></div><p>获取 Rating 最高的 39 首歌曲及总分（参考用）。</p><h3 id="b30-分析" tabindex="-1">B30 分析 <a class="header-anchor" href="#b30-分析" aria-label="Permalink to “B30 分析”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjsk b30</span></span></code></pre></div><p>获取 Rating 最高的 30 首歌曲及平均分（算法不同）。</p></div><hr><h2 id="歌曲进度查询" tabindex="-1">歌曲进度查询 <a class="header-anchor" href="#歌曲进度查询" aria-label="Permalink to “歌曲进度查询”">​</a></h2><div class="command-section"><h3 id="expert-进度" tabindex="-1">Expert 进度 <a class="header-anchor" href="#expert-进度" aria-label="Permalink to “Expert 进度”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjsk进度ex</span></span></code></pre></div><p>查询 <strong>Expert</strong> 难度歌曲完成情况 (AP/FC/Clear)。</p><h3 id="append-进度" tabindex="-1">Append 进度 <a class="header-anchor" href="#append-进度" aria-label="Permalink to “Append 进度”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjsk进度apd</span></span></code></pre></div><p>查询 <strong>Append</strong> 难度歌曲完成情况。</p></div><hr><h2 id="详细信息查询" tabindex="-1">详细信息查询 <a class="header-anchor" href="#详细信息查询" aria-label="Permalink to “详细信息查询”">​</a></h2><div class="command-section"><h3 id="个人详细信息" tabindex="-1">个人详细信息 <a class="header-anchor" href="#个人详细信息" aria-label="Permalink to “个人详细信息”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjskdetail</span></span></code></pre></div><p>获取详细信息，包括：</p><ul><li>金币数量</li><li>水晶数量</li><li>家具收藏</li><li>每日挑战进度</li></ul><blockquote><p><em>介意隐私者可私聊查询</em></p></blockquote><h3 id="卡牌图鉴" tabindex="-1">卡牌图鉴 <a class="header-anchor" href="#卡牌图鉴" aria-label="Permalink to “卡牌图鉴”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjskcard</span></span></code></pre></div><p>获取个人卡牌图鉴。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjskcard+角色名</span></span></code></pre></div><p>查指定角色的卡牌（如：<code>pjskcard+奏</code>）。</p><h3 id="活动历史" tabindex="-1">活动历史 <a class="header-anchor" href="#活动历史" aria-label="Permalink to “活动历史”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjskevent</span></span></code></pre></div><p>获取个人历史最高活动排名记录（近10次）。</p></div><hr><h2 id="指令速查表" tabindex="-1">指令速查表 <a class="header-anchor" href="#指令速查表" aria-label="Permalink to “指令速查表”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><code>rk</code></td><td>排位信息</td><td>当前排位段位和分数</td></tr><tr><td><code>b39</code></td><td>B39 分析</td><td>Rating 最高的 39 首歌</td></tr><tr><td><code>pjsk b30</code></td><td>B30 分析</td><td>不同算法的 B30</td></tr><tr><td><code>pjsk进度ex</code></td><td>Expert 进度</td><td>Expert 难度完成情况</td></tr><tr><td><code>pjsk进度apd</code></td><td>Append 进度</td><td>Append 难度完成情况</td></tr><tr><td><code>pjskdetail</code></td><td>详细信息</td><td>金币/水晶/家具等</td></tr><tr><td><code>pjskcard</code></td><td>卡牌图鉴</td><td>全部或指定角色</td></tr><tr><td><code>pjskevent</code></td><td>活动历史</td><td>近10次活动排名</td></tr></tbody></table><hr><h2 id="多服支持" tabindex="-1">多服支持 <a class="header-anchor" href="#多服支持" aria-label="Permalink to “多服支持”">​</a></h2><p>所有指令都支持多服前缀：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 日服（默认）</span></span>
<span class="line"><span>rk</span></span>
<span class="line"><span>b39</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 台服</span></span>
<span class="line"><span>twrk</span></span>
<span class="line"><span>twb39</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 国服</span></span>
<span class="line"><span>cnrk</span></span>
<span class="line"><span>cnb39</span></span></code></pre></div><hr><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">数据更新</p><p></p><ul><li>数据分析基于你上传的最新数据</li><li>建议定期重新上传以保持数据准确性</li><li>部分数据可能有延迟</li></ul></div><div class="info custom-block github-alert"><p class="custom-block-title">算法说明</p><p></p><ul><li><code>b39</code> 和 <code>pjsk b30</code> 使用不同的 Rating 算法</li><li>结果仅供参考，以游戏内为准</li></ul></div><hr><div class="nav-footer"><a href="./user-data" class="nav-prev">← 上一页：用户数据管理</a><a href="./deck" class="nav-next">下一页：智能卡组推荐 →</a></div>`,25)])])}const b=s(l,[["render",n]]);export{k as __pageData,b as default};
